import{_ as a,o as i,c as o,ae as r}from"./chunks/framework.BalxkeZv.js";const p=JSON.parse('{"title":"架构总览","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1777140393000}'),t={name:"guide/architecture.md"};function l(d,e,c,s,n,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="架构总览" tabindex="-1">架构总览 <a class="header-anchor" href="#架构总览" aria-label="Permalink to &quot;架构总览&quot;">​</a></h1><p>SubForge 采用 <strong>Core + Desktop</strong> 分离架构：</p><ul><li><code>subforge-core</code>：独立守护进程，承载刷新调度、插件运行、聚合转换、HTTP API。</li><li><code>subforge-desktop</code>：可选 GUI，仅用于管理与观察。</li></ul><h2 id="通信边界" tabindex="-1">通信边界 <a class="header-anchor" href="#通信边界" aria-label="Permalink to &quot;通信边界&quot;">​</a></h2><ul><li>管理与数据接口统一通过 Core HTTP API。</li><li>Desktop 的进程生命周期管理走 Tauri IPC。</li><li><code>admin_token</code> 只在 Rust 侧内存中保存，不落入 WebView JS 上下文。</li></ul><h2 id="导出语义" tabindex="-1">导出语义 <a class="header-anchor" href="#导出语义" aria-label="Permalink to &quot;导出语义&quot;">​</a></h2><ul><li>四种订阅读取接口共享同一份最终聚合节点集。</li><li>如果 Profile 绑定了路由模板来源，<code>/api/profiles/{id}/clash</code> 与 <code>/api/profiles/{id}/sing-box</code> 会优先保留模板原有分组与规则结构，再把聚合节点追加到输出节点集和可注入分组中。</li><li><code>/api/profiles/{id}/base64</code> 与 <code>/api/profiles/{id}/raw</code> 始终只暴露最终聚合节点集，不携带模板分流规则。</li></ul><h2 id="运行模式" tabindex="-1">运行模式 <a class="header-anchor" href="#运行模式" aria-label="Permalink to &quot;运行模式&quot;">​</a></h2><ul><li>桌面模式：Desktop 可随时开关，Core 常驻。</li><li>无头模式：仅运行 Core + TOML 配置，适合服务器与容器部署。</li></ul>',9)])])}const _=a(t,[["render",l]]);export{p as __pageData,_ as default};
